1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveSet: ReadonlySet<string>): number =>
15	  neighborsOf(cell).filter((neighbor) => liveSet.has(keyOf(neighbor))).length;
16	
17	const willBeAlive = (cell: Cell, liveSet: ReadonlySet<string>): boolean => {
18	  const count = countLiveNeighbors(cell, liveSet);
19	  return liveSet.has(keyOf(cell))
20	    ? count === 2 || count === 3
21	    : count === 3;
22	};
