24	export function nextGeneration(liveCells: Cell[]): Cell[] {
25	  const liveSet = new Set(liveCells.map(keyOf));
26	
27	  const candidates = new Map<string, Cell>();
28	  for (const cell of liveCells) {
29	    candidates.set(keyOf(cell), cell);
30	    for (const neighbor of neighborsOf(cell)) {
31	      candidates.set(keyOf(neighbor), neighbor);
32	    }
33	  }
34	
35	  return [...candidates.values()].filter((cell) => willBeAlive(cell, liveSet));
36	}
