33	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
34	    // L-shape: (0,0), (1,0), (0,1) -> dead cell (1,1) has 3 live neighbors -> alive
35	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
